class MyResponseDetailPage{constructor(){this.responseId=null,this.surveyId=null,this.init()}async init(){if(!window.app.isLoggedIn())return void(window.location.href="/login");const e=window.location.pathname.split("/");this.responseId=parseInt(e[e.length-1]),this.responseId?(this.setupEventListeners(),await this.loadResponseDetail()):window.location.href="/surveys/my"}setupEventListeners(){const e=document.getElementById("logout-btn");e&&e.addEventListener("click",()=>window.app.logout())}async loadResponseDetail(){const e=document.getElementById("loading"),t=document.getElementById("error-message"),s=document.getElementById("response-container");if(e&&t&&s)try{e.classList.remove("hidden"),t.classList.add("hidden"),s.classList.add("hidden");const n=await window.app.apiRequest(`/surveys/responses/${this.responseId}/data`),i=document.getElementById("survey-title"),d=document.getElementById("survey-description"),o=document.getElementById("response-date");i&&(i.textContent=n.survey.title),d&&(d.textContent=n.survey.description||""),o&&(o.textContent=new Date(n.submitted_at).toLocaleDateString("ru-RU")),this.renderAnswers(n.answers,n.questions),e.classList.add("hidden"),s.classList.remove("hidden")}catch(s){e.classList.add("hidden"),t.classList.remove("hidden"),t.textContent="Ошибка загрузки ответов."}}renderAnswers(e,t){const s=document.getElementById("answers-list");if(s.innerHTML="",!e||!Array.isArray(e))return void(s.innerHTML='<div class="error-message">Нет доступных ответов</div>');const n={};e.forEach(e=>{n[e.question_id]=e}),t.forEach((e,t)=>{const i=n[e.id],d=document.createElement("div");d.className="answer-item";let o="";i?"text"===e.type?o=`<p class="answer-text">${i.value}</p>`:"single_choice"===e.type&&(o=`<p class="answer-choice">${i.value}</p>`):o='<p class="no-answer">Нет ответа</p>',d.innerHTML=`\n                <div class="answer-header">\n                    <h4>Вопрос ${t+1}</h4>\n                </div>\n                <div class="answer-content">\n                    <p class="question-text">${e.text}</p>\n                    ${o}\n                </div>\n            `,s.appendChild(d)})}}document.addEventListener("DOMContentLoaded",()=>{new MyResponseDetailPage});